INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('92c6ac6c-fd52-5927-bf49-9aa09fa8146a', '6ba8bebb-72f7-41c5-ae30-b931d133d6d2', 'It is your ___ to roll the dice.', '輪到你擲骰子了。', 'go', 'time', 'way', 'game', 'go 當作名詞時，有「輪到某人的機會」之意。', 'It is your go = It is your turn (輪到你了)'),
('44c21051-1844-5201-955d-206bfd47546e', '274ca5ba-aa7f-4abf-ac77-854aac1e695e', 'I ___ a new bicycle.', '我有一輛新腳踏車。', 'have', 'want', 'like', 'need', 'have 表示「擁有」。', '想像手裡握著某樣東西。'),
('7a7ba371-5d89-52ea-8600-85f16fadb08a', '78c8571f-9d90-4e82-9f1d-9eba115d2be3', 'The books are ___ the bag.', '書在包包裡面。', 'in', 'on', 'at', 'by', '(介係詞) 表示在某個空間或容器裡面。', '想像東西被裝在盒子裡面。'),
('d88649f0-fe70-50c8-88eb-6aeb74d4c606', '24837458-0d4f-4a59-9dc7-ae944f0f278c', 'The number of students in the classroom ___ twenty.', '教室裡的學生人數是二十人。', 'is', 'has', 'does', 'says', 'be 動詞的第三人稱單數現在式', 'is 代表「是」或「在」，用於描述主詞的狀態或身分。'),
('2a34d4a4-5c9c-5beb-a101-ebd4ae111972', '8fecc1f7-8571-4e65-874e-7bec724d9609', '___ capital of France is Paris.', '法國的首都是巴黎。', 'The', 'A', 'Some', 'Any', '定冠詞 (Definite Article)', '指特定、唯一的對象用 the'),
('afd50e99-9a1e-5498-809b-612fb2514de6', 'a3111bfd-ea64-4091-821d-6c37f0f00a34', 'I will meet you ___ the bus stop.', '我會在公車站跟你見面。', 'at', 'in', 'on', 'to', '介系詞', 'at 用於指特定的地點或位置。'),
('be435848-8d88-5fa3-b488-1a4970a1d32a', 'bbb2fcee-f431-417f-9611-641469dcd9d1', 'The problem is not the cost, ___ the quality.', '問題不在於成本，而在於品質。', 'but', 'and', 'so', 'or', 'conj. (連接詞) 常與 not 連用，構成「不是...而是...」的結構。', 'not... but... 結構表示「不是...而是...」→ but');
